const createPlayerStats = () => {
    return {
        // --- Stats ---
        attack: 1,
        defense: 1,
        hp: 10,

        // --- Potential Stats ---
        attackPotential: 0,
        defensePotential: 0,
        hpPotential: 0,

        // --- Resource ---
        statPoints: 0,

        // --- Upgrade Functions ---
        upgradeAttack: function() {
            if (this.statPoints >= 1) {
                this.statPoints -= 1;
                this.attack += (1 + this.attackPotential);
                return { success: true, updatedStats: this.getCurrentStats() };
            } else {
                return { success: false, message: "Not enough Stat Points!" };
            }
        },

        upgradeDefense: function() {
            if (this.statPoints >= 1) {
                this.statPoints -= 1;
                this.defense += (1 + this.defensePotential);
                return { success: true, updatedStats: this.getCurrentStats() };
            } else {
                return { success: false, message: "Not enough Stat Points!" };
            }
        },

        upgradeHp: function() {
            if (this.statPoints >= 1) {
                this.statPoints -= 1;
                this.hp += (1 + this.hpPotential);
                return { success: true, updatedStats: this.getCurrentStats() };
            } else {
                return { success: false, message: "Not enough Stat Points!" };
            }
        },

        upgradeAttackPotential: function() {
            if (this.statPoints >= 1) {
                this.statPoints -= 1;
                this.attackPotential += 1;
                return { success: true, updatedStats: this.getCurrentStats() };
            } else {
                return { success: false, message: "Not enough Stat Points!" };
            }
        },

        upgradeDefensePotential: function() {
            if (this.statPoints >= 1) {
                this.statPoints -= 1;
                this.defensePotential += 1;
                return { success: true, updatedStats: this.getCurrentStats() };
            } else {
                return { success: false, message: "Not enough Stat Points!" };
            }
        },

        upgradeHpPotential: function() {
            if (this.statPoints >= 1) {
                this.statPoints -= 1;
                this.hpPotential += 1;
                return { success: true, updatedStats: this.getCurrentStats() };
            } else {
                return { success: false, message: "Not enough Stat Points!" };
            }
        },

        // --- Method to add Stat Points ---
        addStatPoints: function(amount) {
            this.statPoints += amount;
            return this.getCurrentStats(); // Return updated stats for UI update
        },

        // --- Helper function to get current stats (for convenience) ---
        getCurrentStats: function() {
            return {
                attack: this.attack,
                defense: this.defense,
                hp: this.hp,
                attackPotential: this.attackPotential,
                defensePotential: this.defensePotential,
                hpPotential: this.hpPotential,
                statPoints: this.statPoints
            };
        },
    };
};

export default createPlayerStats;
